import React from "react";

export const Services = (props) => {
  const d = props.data;
  const items = d && d.items ? d.items : (Array.isArray(d) ? d : []);
  const title = d && d.title ? d.title : "Serviços";
  const subtitle = d && d.subtitle ? d.subtitle : "";

  return (
    <div id="services" className="text-center 55lab-services">
      <div className="container">
        <div className="section-title">
          <h2>{title}</h2>
          {subtitle ? <p>{subtitle}</p> : null}
        </div>
        <div className="row">
          {items.map((item, i) => (
            <div key={`${item.name}-${i}`} className="col-xs-12 col-sm-6 col-md-3">
              <i className={item.icon} aria-hidden="true"></i>
              <div className="service-desc">
                <h3>{item.name}</h3>
                <p>{item.text}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};
